                L_ptr[i * n + j] = 1.0
            else:
                L_ptr[i * n + j] = 0.0
            if i <= j:
                U_ptr[i * n + j] = A_ptr[i * n + j]
            else:
                U_ptr[i * n + j] = 0.0

    # LU decomposition with partial pivoting
    for k in range(n):
        # Find pivot
        max_val = 0.0
        pivot_idx = k
        for i in range(k, n):
            val = tl.abs(U_ptr[i * n + k])
            if val > max_val:
                max_val = val
                pivot_idx = i

        # Swap rows in A, L, U, and pivot array
