            for j in range(n):
                temp = U_ptr[k * n + j]
                U_ptr[k * n + j] = U_ptr[pivot_idx * n + j]
                U_ptr[pivot_idx * n + j] = temp

                temp = L_ptr[k * n + j]
                L_ptr[k * n + j] = L_ptr[pivot_idx * n + j]
                L_ptr[pivot_idx * n + j] = temp

            # Update pivot array
            temp = pivot_ptr[k]
            pivot_ptr[k] = pivot_ptr[pivot_idx]
            pivot_ptr[pivot_idx] = temp

        # Compute L and U
